styles.css:
/* Styles pour les métadonnées de recettes */
.meta-recette {
    background-color: #f9f9f9;
    padding: 20px;
    border-radius: 8px;
    margin: 20px 0;
}

.meta-recette p {
    margin: 10px 0;
}

.ingredients {
    margin-top: 20px;
    padding: 15px;
    background-color: #fff;
    border-left: 4px solid var(--wp--preset--color--primary);
}

/* Styles pour la grille de recettes */
.wp-block-post-template {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
    gap: 30px;
}

/* Styles généraux du thème */
body {
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    font-size: 16px;
    color: #333333;
    margin: 0 20px; /* marge gauche/droite de 20px */
    padding: 0;
    background: linear-gradient(to bottom, #f0f0f0, #ffffff); /* dégradé gris vers blanc */
}

/* Header */
.site-header {
    margin: 0 20px; /* marge gauche/droite */
    padding: 20px 0;
}

/* Conteneur principal */
.site {
    max-width: 1200px;
    margin: 0 auto;
    padding: 20px;
}

/* Footer */
.site-footer {
    margin: 0 20px; /* marge gauche/droite */
    text-align: center;
    padding: 40px 0;
    background-color: #f2f2f2;
    color: #666666;
}

/* Liens */
a {
    color: #4ECDC4; /* couleur secondaire */
    text-decoration: none;
}

a:hover {
    text-decoration: underline;
}

/* Titres */
h1, h2, h3, h4, h5, h6 {
    color: #222222;
    margin-top: 1.2em;
    margin-bottom: 0.6em;
    line-height: 1.3;
}

/* Paragraphes */
p {
    line-height: 1.6;
    margin-bottom: 1em;
}

/* Images mises en avant */
.wp-block-post-featured-image img {
    max-width: 100%;
    height: auto;
    border-radius: 8px;
    margin-bottom: 20px;
}

/* Styles pour les métadonnées des recettes */
.champs-recette {
    background-color: #fafafa;
    padding: 20px;
    border-radius: 8px;
    margin: 20px 0;
    border-left: 4px solid #FF6B6B; /* couleur primaire */
}

.champs-recette-row {
    display: flex;
    justify-content: space-between;
    margin-bottom: 10px;
}

.champs-recette-label {
    font-weight: bold;
    color: #555555;
}

.champs-recette-value {
    color: #333333;
}

/* Section ingrédients */
.ingredients {
    background-color: #ffffff;
    border-left: 4px solid #4ECDC4; /* couleur secondaire */
    padding: 15px;
    margin-top: 20px;
    border-radius: 6px;
}

.ingredients h3 {
    margin-top: 0;
}

/* Grille des articles / archives */
.wp-block-post-template {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
    gap: 30px;
}
